@js:
java.toast("\n 正在进行发现页更新...");
let list = [];
const push = (title, url, size) => list.push({
    "title": title,
    "url": url,
    "style": {
        "layout_flexGrow": 1,
        "layout_flexBasisPercent": size
    }
});

const html = org.jsoup.Jsoup.parse(java.ajax(source.getKey()));
const reg = /^\/category\/[0-9a-z]+\/[0-9]\/$/;
let items = html.select("ul.dx-container > li");
for (let i = 0; i < items.size(); i++) {
    let el = items.get(i);
    let a = el.select("a");
    if (a.isEmpty()) continue;

    let href = a.attr("href");
    if (reg.test(href)) {
        let title = a.text();
        push(title, href.replace("/1/", `/{{page}}/`), 0.3);
    }   
}

JSON.stringify(list);

